// parseDuration(s): parse one or more <number><unit> segments into total
// seconds. Units: h=3600s, m=60s, s=1s. Whitespace is not allowed; an empty
// string or any invalid format throws.
const UNIT = { h: 3600, m: 60, s: 1 };

function parseDuration(s) {
  if (typeof s !== "string" || s.length === 0) {
    throw new Error("parseDuration: empty or non-string input");
  }
  if (!/^(\d+[hms])+$/.test(s)) {
    throw new Error(`parseDuration: invalid format: ${JSON.stringify(s)}`);
  }
  let total = 0;
  for (const m of s.matchAll(/(\d+)([hms])/g)) {
    total += Number(m[1]) * UNIT[m[2]];
  }
  return total;
}
module.exports = { parseDuration };
